package metodos.oop.exercicios.test;import metodos.oop.exercicios.domain.Usuario;import java.util.Scanner;public class UsuarioTest {    public static void main(String[] args) {        Scanner input = new Scanner(System.in);        Usuario usuario = new Usuario();        System.out.println("User: ");        usuario.nameUser = input.nextLine();        System.out.println("Password: ");        usuario.password = input.nextLine();        System.out.println(usuario.verifyUser(usuario.nameUser, usuario.password));    }}